def compute_stats(data, prefix=None, round_digits=None, label=None):
    """
    Compute statistics for data.

    - If prefix is provided (e.g. 'raw'), returns keys with that prefix:
        {"raw_mean": ..., "raw_max": ..., "raw_min": ..., "raw_range": ...}

    - If round_digits is provided (e.g. 1) returns a display-friendly summary:
        {"avg": rounded_mean, "peak": rounded_max, "label": label_or_'processed'}

    - If neither prefix nor round_digits is provided, returns full stats without prefix.

    Handles empty data by returning zeros in the expected shape.
    """
    if not data:
        if prefix:
            return {
                f"{prefix}_mean": 0.0,
                f"{prefix}_max": 0.0,
                f"{prefix}_min": 0.0,
                f"{prefix}_range": 0.0,
            }
        if round_digits is not None:
            return {"avg": 0.0, "peak": 0.0, "label": label or "processed"}
        return {"mean": 0.0, "max": 0.0, "min": 0.0, "range": 0.0}

    mean = sum(data) / len(data)
    max_v = max(data)
    min_v = min(data)
    range_v = max_v - min_v

    if prefix:
        return {
            f"{prefix}_mean": mean,
            f"{prefix}_max": max_v,
            f"{prefix}_min": min_v,
            f"{prefix}_range": range_v,
        }

    if round_digits is not None:
        return {"avg": round(mean, round_digits), "peak": round(max_v, round_digits), "label": label or "processed"}

    return {"mean": mean, "max": max_v, "min": min_v, "range": range_v}


def compute_quality_score(cleaned_data):
    n_zeros = sum(1 for x in cleaned_data if x == 0)
    return 1.0 - (n_zeros / len(cleaned_data)) if cleaned_data else 0.0
```

