def compute_stats(data, display=False):
    """
    Compute either raw stats or a display-friendly summary for the provided data.

    If display is False, returns a dict with keys:
      - raw_mean, raw_max, raw_min, raw_range

    If display is True, returns a dict with keys:
      - avg (rounded to 1 decimal), peak (rounded to 1 decimal), label
    """
    if not data:
        if display:
            return {"avg": 0.0, "peak": 0.0, "label": "processed"}
        return {"raw_mean": 0.0, "raw_max": 0.0, "raw_min": 0.0, "raw_range": 0.0}

    mean = sum(data) / len(data)
    maximum = max(data)
    minimum = min(data)
    rng = maximum - minimum

    if display:
        return {"avg": round(mean, 1), "peak": round(maximum, 1), "label": "processed"}

    return {"raw_mean": mean, "raw_max": maximum, "raw_min": minimum, "raw_range": rng}


def compute_quality_score(cleaned_data):
    n_zeros = sum(1 for x in cleaned_data if x == 0)
    return 1.0 - (n_zeros / len(cleaned_data)) if cleaned_data else 0.0


# Backwards-compatible wrappers
def compute_raw_stats(data):
    return compute_stats(data, display=False)


def summarize_for_display(data):
    return compute_stats(data, display=True)
