```python
import threading

# Centralized counter and lock
_value = 0
_lock = threading.Lock()


def get_counter():
    """Return the current counter value (thread-safe)."""
    with _lock:
        return _value


def increment(n=1):
    """Atomically add n to the counter. n is coerced to int if possible.

    Raises TypeError if n cannot be converted to int.
    """
    global _value
    try:
        n = int(n)
    except Exception as exc:
        raise TypeError("increment requires an integer value") from exc
    with _lock:
        _value += n


def reset():
    """Reset the counter to zero (thread-safe)."""
    global _value
    with _lock:
        _value = 0
