from state import increment, get_counter


def quick_increment(item):
    """Increment counter by item['weight'].

    Returns a dict with status. Performs lightweight validation of 'weight'.
    """
    if not isinstance(item, dict) or "weight" not in item:
        return {"status": "error", "reason": "missing weight"}
    try:
        weight = int(item["weight"])
    except Exception:
        return {"status": "error", "reason": "invalid weight"}
    increment(weight)
    return {"status": "ok"}


