def _validate_items(items):
    """Validate items have integer-convertible 'weight' fields.

    Raises ValueError on invalid items.
    """
    for i, item in enumerate(items):
        if not isinstance(item, dict) or "weight" not in item:
            raise ValueError(f"item at index {i} missing 'weight'")
        try:
