from store import clear, get, upsert, apply_delta, get_apply_log


def ingest(events, max_retries=3):
    """
    Robust per-event processing with rollback on failure and retries.

    - Clears the store (same as previous behavior).
    - For each event, snapshots original value and tries the operation up to max_retries.
    - If an attempt raises an exception, restores the original value before retrying.
    - Returns the list of resulting values (or None for events that ultimately failed)
      and the audit log count.
    """
    clear()
    results = []

    for e in events:
        key = e.get("key")
        success = False
        final_value = None

        # Snapshot the original value so we can restore on failure
        original = get(key)

        for attempt in range(max_retries):
            try:
                if e["type"] == "set":
                    # try set; if it raises, restore original and retry
                    upsert(key, e["value"])
                elif e["type"] == "adjust":
                    # try adjust; if it raises, restore original and retry
                    apply_delta(key, e["delta"])
                else:
                    # unknown event type => treat as failure
                    raise ValueError(f"unknown event type: {e.get('type')}")

                # If operation succeeded, record result and break
                final_value = get(key)
                success = True
                break

            except Exception:
                # On any exception, attempt to restore the original value before retrying.
                # This implements explicit rollback so retries don't leave partial state.
                try:
                    upsert(key, original)
                except Exception:
                    # Best-effort restore; swallow exceptions to continue retrying.
                    pass
                continue

        results.append(final_value if success else None)

    trail = get_apply_log()
    return {"results": results, "audit_count": len(trail)}


def ingest_with_retry(events):
    # keep older helper for compatibility; uses the handler-style per-event wrapper
    clear()
    results = []
    for e in events:
        # naive wrapper left in place; prefer using ingest(...) above for robust behavior
        # here we just attempt to run the event once via the simple handler-style interface
        try:
            # try to use same logic as ingest but only a single attempt
            if e["type"] == "set":
                upsert(e["key"], e["value"])
                results.append(get(e["key"]))
            elif e["type"] == "adjust":
                apply_delta(e["key"], e["delta"])
                results.append(get(e["key"]))
            else:
                results.append(None)
        except Exception:
            results.append(None)
    trail = get_apply_log()
    return {"results": results, "audit_count": len(trail)}
