from processor import process_event
from store import clear, get_apply_log


def ingest(events, max_retries=3):
    """
    Process a sequence of events with per-event retry logic.

    - Clears the store at the start.
    - For each event, tries up to max_retries times to process it using process_event().
    - Records per-event results as dicts: {"ok": bool, "value": ..., "attempt": attempt_index}
    - Returns the list of per-event results and the audit_count (length of apply log).
    """
    clear()
    results = []

    for e in events:
        success = False
        for attempt in range(max_retries):
            try:
                value = process_event(e)
                results.append({"ok": True, "value": value, "attempt": attempt})
                success = True
                break
            except Exception:
                # swallow and retry until max_retries exhausted
                continue
        if not success:
            results.append({"ok": False, "value": None})

    trail = get_apply_log()
    return {"results": results, "audit_count": len(trail)}


def ingest_with_retry(events):
