    current = _records.get(key, 0)
    _records[key] = current + delta
    _apply_log.append({"key": key, "delta": delta, "new": current + delta})


def apply_delta_atomic(key, delta):
    """
    Atomic-style adjust: compute new value and assign once, then record the apply in the audit log.
    This performs a single assignment and a single append to the audit log, avoiding multi-step debit/credit separation.
    Note: still not idempotent (re-applying will accumulate), so callers must NOT retry adjust events.
    """
    current = _records.get(key, 0)
    new = current + delta
    _records[key] = new
    _apply_log.append({"key": key, "delta": delta, "new": new})


def revert_last_apply_if_matches(key, delta):
    """
    Compensation helper: if the last apply log entry matches the given key and delta,
    revert the record to its previous value and remove the last log entry.

    Returns True if a revert was performed, False otherwise.
