    if not _apply_log:
        return False
    last = _apply_log[-1]
    if last.get("key") == key and last.get("delta") == delta:
        # previous value = new - delta
        prev = last.get("new") - delta
        _records[key] = prev
        _apply_log.pop()
        return True
    return False


def get_apply_log():
    return list(_apply_log)


def clear():
    _records.clear()
    _apply_log.clear()
