from threading import RLock

_records = {}
_apply_log = []
_lock = RLock()


def upsert(key, value):
    """Set the value for key."""
    _records[key] = value


def get(key):
    return _records.get(key)


def apply_delta(key, delta):
    current = _records.get(key, 0)
    _records[key] = current + delta
    _apply_log.append({"key": key, "delta": delta, "new": current + delta})


def get_apply_log():
    return list(_apply_log)


def clear():
    """Clear all store state in a thread-safe manner."""
    with _lock:
        _records.clear()
        _apply_log.clear()


# Transaction utilities for atomic attempts and concurrency control
def transaction():
    """Return a lock suitable for use with `with transaction():` to serialize access."""
    return _lock


def snapshot():
    """Return a deep-enough snapshot of the store state for rollback.

    The snapshot is a tuple (records_copy, apply_log_copy).
    """
    # We don't deep-copy values inside records because callers of store functions
    # expect their behavior to mirror the original store; this is sufficient for
    # testing with simple primitives and preserves order semantics.
    with _lock:
        return dict(_records), list(_apply_log)


def restore(snapshot_state):
    """Restore the store to a previously taken snapshot state.

    snapshot_state should be the value returned by snapshot().
    """
    records_copy, apply_log_copy = snapshot_state
    with _lock:
        _records.clear()
        _records.update(records_copy)
        _apply_log.clear()
        _apply_log.extend(apply_log_copy)
