from handler import handle_batch, get_audit_trail
from store import clear, transaction, snapshot, restore, get_apply_log


def ingest(events):
    """Process a list of events with per-event retry and atomic commit.

    This preserves the original ingest signature and result structure
    ({"results": [...], "audit_count": N}). For each event we will:
      - take a snapshot of the store,
      - attempt to process the event while holding the store transaction lock,
      - on exception, restore the snapshot and retry up to MAX_RETRIES,
      - if all retries fail, re-raise the last exception to preserve
        the original error behavior.

    Side effects are committed in the original event order.
    """
    clear()
    results = []
    MAX_RETRIES = 3

    for e in events:
        last_exc = None
        succeeded = False
        for attempt in range(MAX_RETRIES):
            # Acquire the store lock for the whole attempt so partial
            # modifications aren't visible to other threads.
            with transaction():
                snap = snapshot()
                try:
                    res = process_event(e)
                    results.append(res)
                    succeeded = True
                    break
                except Exception as exc:
                    # Roll back any partial changes made during this attempt
                    restore(snap)
                    last_exc = exc
                    # continue to retry
                    continue
        if not succeeded:
            # After exhausting retries, re-raise to preserve original behavior
            raise last_exc

    trail = get_audit_trail()
    return {"results": results, "audit_count": len(trail)}


def ingest_with_retry(events):
    clear()
    results = []
    for e in events:
        results.append(handle_with_retry(e))
    trail = get_audit_trail()
    return {"results": results, "audit_count": len(trail)}
