from store import upsert, apply_delta, get, get_apply_log


def process_event(event):
    if event["type"] == "set":
        # sets are idempotent: writing the same value again is safe
        upsert(event["key"], event["value"])
    elif event["type"] == "adjust":
        # To make retries safe, check whether the same adjustment was already
        # recorded as the most recent apply entry. If so, assume a prior
        # attempt succeeded and skip re-applying the delta. This prevents
        # double-application on retry while preserving ordering.
        log = get_apply_log()
        if log and log[-1]["key"] == event["key"] and log[-1]["delta"] == event["delta"]:
            # The adjustment was already applied by a previous attempt; skip
            pass
        else:
            apply_delta(event["key"], event["delta"])
    return get(event["key"])


def safe_set(event):
    upsert(event["key"], event["value"])
    return get(event["key"])


def replay_events(events):
    results = []
    for e in events:
        results.append(process_event(e))
    return results
