def ingest(events, max_retries=3):
    """
    Clear state and process events sequentially with robust retry logic.

    For each event, attempt up to max_retries to process it. If processing
    an event ultimately fails, stop processing further events to preserve
    ordering and return the results collected so far.

    Returns a dict with keys:
      - results: list of per-event result dicts {ok, value, attempt(s)}
      - audit_count: number of entries in the apply log
    """
    clear()
    results = []

    for e in events:
        success = False
        for attempt in range(max_retries):
            try:
                value = process_event(e)
                results.append({"ok": True, "value": value, "attempt": attempt})
                success = True
                break
            except Exception:
                # try again until attempts exhausted
                continue

        if not success:
            # permanent failure for this event after retries; abort to preserve ordering
            results.append({"ok": False, "value": None, "attempts": max_retries})
            break

    trail = get_audit_trail()
    return {"results": results, "audit_count": len(trail)}


def ingest_with_retry(events, max_retries=3):
    # keep compatibility: delegate to the new ingest implementation
    return ingest(events, max_retries=max_retries)
