from processor import process_event
from store import clear


def ingest(events, max_retries=3):
    """Process a batch of events with per-event retries.

    Behavior:
    - The store is cleared at the start (same as original ingest()).
    - Events are applied in-order to the real store.
    - Each event is retried up to max_retries on exception.
    - If an event exhausts retries, the exception is re-raised (so the
      function fails fast and leaves the store in its partial state),
      which mirrors the original ingest() behavior on error.
    """
    clear()
    results = []
    for e in events:
        for attempt in range(max_retries):
            try:
                results.append(process_event(e))
                break
            except Exception:
                # If this was the last allowed attempt, re-raise so callers
                # observe the failure (like the original ingest()).
                if attempt == max_retries - 1:
                    raise
                # otherwise, try again
                continue
    trail = get_audit_trail()
    return {"results": results, "audit_count": len(trail)}


def ingest_with_retry(events):
    clear()
    results = []
    for e in events:
        results.append(handle_with_retry(e))
    trail = get_audit_trail()
    return {"results": results, "audit_count": len(trail)}
