from store import upsert, apply_delta, get, is_processed


def process_event(event):
    """
    Process a single event. If the event has an 'id' and that id has already been
    processed, the function returns the current value without reapplying the event.
    """
    eid = event.get("id")
    if eid is not None and is_processed(eid):
        return get(event["key"])

    if event["type"] == "set":
        upsert(event["key"], event["value"], event_id=eid)
    elif event["type"] == "adjust":
        apply_delta(event["key"], event["delta"], event_id=eid)
    return get(event["key"])


def safe_set(event):
    upsert(event["key"], event["value"], event_id=event.get("id"))
    return get(event["key"])


def replay_events(events):
    results = []
    for e in events:
        results.append(process_event(e))
    return results
