from processor import process_event, replay_events
from store import get_apply_log


def handle_with_retry(event, max_retries=3):
    """
    Try to process an event up to max_retries times. Processing is idempotent
    when events carry an 'id'. Returns a dict describing success/failure.
    """
    last_exc = None
    for attempt in range(1, max_retries + 1):
        try:
            result = process_event(event)
            return {"ok": True, "value": result, "attempts": attempt}
        except Exception as exc:
            last_exc = exc
            continue
    return {"ok": False, "value": None, "error": str(last_exc)}


def handle_batch(events):
    return replay_events(events)


def get_audit_trail():
    return get_apply_log()
