from store import clear


def ingest(events):
    """
    Ingest a sequence of events, clearing store first. Each event is processed with
    retries via handle_with_retry. If an event fails after retries, the call returns
    immediately with the partial results and indicates failure.
    """
    clear()
    results = []
    for e in events:
        res = handle_with_retry(e)
        if not res.get("ok"):
            # Stop on unrecoverable failure for this event stream and return what we have
            return {"results": results + [res], "audit_count": len(get_audit_trail()), "ok": False}
        results.append(res)
    trail = get_audit_trail()
    return {"results": results, "audit_count": len(trail), "ok": True}


def ingest_with_retry(events):
    """
    Simpler variant that uses handle_with_retry on each event but always returns
    the per-event outcomes (does not short-circuit on a failed event).
    """
    clear()
    results = []
    for e in events:
        results.append(handle_with_retry(e))
    trail = get_audit_trail()
    return {"results": results, "audit_count": len(trail)}
