def place_order(order_id, sku, qty, price):
    """
    Core business operation: reserve inventory and charge wallet.
    This function does NOT perform notifications. It ensures that if
    charging fails after reserving, the reservation is rolled back.
    """
    total = qty * price

    # Reserve inventory first. If this raises, nothing to roll back.
    inventory.reserve(sku, qty)

    # Attempt to charge. If charging fails we must restore the reservation.
    try:
        wallet.charge(total)
    except Exception:
        # Restore inventory on any failure to keep system consistent.
        inventory.release(sku, qty)
        raise

    return {"order_id": order_id, "charged": total, "reserved": qty}


def cancel_order(order_id, sku, qty, price):
    # Compensation / rollback operation: release inventory and refund wallet
    inventory.release(sku, qty)
    wallet.refund(qty * price)
