```python
# Eagerly create settings at import time and preserve dict identity on reset.
_defaults = {"timeout": 30, "retries": 3, "debug": False}

# Single mutable settings dict, created eagerly.
_settings = dict(_defaults)


def get_settings():
    """Return the shared settings dict (mutable). Keep a single dict object so
    callers that keep references see updates and resets."""
    return _settings


def _load_defaults():
    """Return a fresh copy of the default settings."""
    return dict(_defaults)


def override_settings(overrides):
    """Update settings with overrides. Validate types to avoid subtle runtime errors.

    Allowed keys: 'timeout' (int), 'retries' (int), 'debug' (bool).
    This function raises TypeError/KeyError/ValueError for invalid input.
    """
    if not isinstance(overrides, dict):
        raise TypeError("overrides must be a dict")

    for k, v in overrides.items():
        if k not in ("timeout", "retries", "debug"):
            raise KeyError(f"Unknown setting '{k}'")
        if k in ("timeout", "retries"):
            # bool is a subclass of int; reject bool for these keys.
            if not isinstance(v, int) or isinstance(v, bool):
                raise ValueError(f"'{k}' must be an int (not bool)")
        else:  # k == 'debug'
            if not isinstance(v, bool):
                raise ValueError("'debug' must be a bool")

    _settings.update(overrides)


def reset():
    """Reset the existing settings dict to defaults while preserving object identity."""
    _settings.clear()
    _settings.update(_load_defaults())
