import time

_cache = {}
_fetch_ts = {}
TTL = 5


def fetch_price(symbol, max_age=None):
    """
    Fetch the price for symbol.

    If max_age is provided, use it as the freshness threshold (in seconds).
    Otherwise, use the module TTL.
