from writer import write_record, write_with_retry, safe_write
from store import get_seq, clear, get


def ingest_batch(records, max_retries=3):
    """
    Ingest a batch of records. Each record will be attempted up to max_retries times
    at the batch level; each attempt will itself use write_with_retry which has its
    own internal retries. If a record cannot be written after max_retries attempts,
    a ConnectionError is raised for that record.
    """
    clear()
    results = []
    for r in records:
        last_exc = None
        for attempt in range(max_retries):
            try:
                seq = write_with_retry(r["key"], r["value"])
                break
            except ConnectionError as e:
                last_exc = e
                # try again (outer retry)
                continue
        else:
            # exhausted attempts for this record
            raise ConnectionError(f"failed to write record {r['key']} after {max_retries} attempts") from last_exc

        results.append({"key": r["key"], "seq": seq})
    return {"results": results, "final_seq": get_seq()}


def ingest_safe(records):
    clear()
    results = []
    for r in records:
        seq = safe_write(r["key"], r["value"])
        results.append({"key": r["key"], "seq": seq})
    return {"results": results, "final_seq": get_seq()}"}

