                seq = write_with_retry(r['key'], r['value'], max_retries=per_call_retries)
                results.append({'key': r['key'], 'seq': seq})
                break
            except ConnectionError as e:
                last_exc = e
                # retry this record (do not clear store)
                continue
        else:
            # exhausted attempts for this record
            raise ConnectionError(f"failed to write key {r['key']} after {max_retries_per_record} retries") from last_exc
