import copy

_items = {}
_seq = 0


def insert(key, value):
    global _seq
    _seq += 1
    _items[key] = {"value": value, "seq": _seq}
    return _seq


def get(key):
    return _items.get(key)


def exists(key):
    return key in _items


def get_seq():
    return _seq


def clear():
    global _seq
    _items.clear()
    _seq = 0


def snapshot_state():
    """Return a deep copy snapshot of the current store state.

    The snapshot is a tuple (items_copy, seq) and can be passed to restore_state.
    """
    return (copy.deepcopy(_items), _seq)


def restore_state(snapshot):
    """Restore the store to a previously taken snapshot.

    The snapshot must be one previously returned from snapshot_state().
    """
    global _seq
    items_copy, seq = snapshot
    _items.clear()
    _items.update(items_copy)
    _seq = seq
