from writer import write_with_retry, safe_write
import store
import types


def ingest_batch(records, max_retries=3):
    """
    Build a local (ephemeral) store, attempt all writes with retries against that
    local store, then atomically commit the new state to the global store only if
    all writes succeed. This avoids mutating the global store on partial failure.
    """
    # local ephemeral state
    temp_items = {}
    temp_seq = 0

    def _insert_local(key, value):
        nonlocal temp_seq
        if key in temp_items:
            return temp_items[key]["seq"]
        temp_seq += 1
        temp_items[key] = {"value": value, "seq": temp_seq}
        return temp_seq

    def _exists_local(key):
        return key in temp_items

    def _get_local(key):
        return temp_items.get(key)

    # Build a simple namespace that exposes the minimal store API used by writer
    local_store = types.SimpleNamespace(
        insert=_insert_local,
        exists=_exists_local,
        get=_get_local,
        get_seq=lambda: temp_seq,
    )

    results = []

    # Attempt all writes against the local store using writer's retry machinery.
    # If any record ultimately fails, nothing is committed to the global store.
    for r in records:
        seq = write_with_retry(r["key"], r["value"], max_retries=max_retries, store=local_store)
        results.append({"key": r["key"], "seq": seq})

    # All writes succeeded locally. Commit atomically to global store.
    # Make a shallow copy to avoid external mutation after commit call.
    store.commit(temp_items.copy(), temp_seq)
    return {"results": results, "final_seq": store.get_seq()}


def ingest_safe(records):
    # preserve original behavior (mutates global store immediately)
    store.clear()
    results = []
    for r in records:
        seq = safe_write(r["key"], r["value"], store=store)
        results.append({"key": r["key"], "seq": seq})
    return {"results": results, "final_seq": store.get_seq()}"}

