            seq = write_record(key, value)
            return seq
        except ConnectionError:
            # It's possible the write actually succeeded but the caller saw an error; check existence
            if exists(key):
                return get(key)["seq"]
            continue
    raise ConnectionError(f"failed after {max_retries} retries")
