from writer import write_record, write_with_retry, safe_write
from store import get_seq, clear, get


def ingest_batch(records, max_retries=3):
    """Ingest a batch of records. Each record write is retried up to max_retries.
    Returns results with sequence numbers and the final sequence counter."""
    clear()
    results = []
    for r in records:
        # Per-record retry loop to make the batch ingestion more robust against transient failures
        for attempt in range(max_retries):
            try:
                seq = write_with_retry(r["key"], r["value"], max_retries=max_retries)
                break
            except ConnectionError:
                # Check if the key is present despite the error (the insert may have actually succeeded)
                existing = get(r["key"])
                if existing:
                    seq = existing["seq"]
                    break
                if attempt == max_retries - 1:
                    raise ConnectionError(f"failed to write record {r['key']} after {max_retries} retries")
                # otherwise, try again
                continue
        results.append({"key": r["key"], "seq": seq})
    return {"results": results, "final_seq": get_seq()}


def ingest_safe(records):
    clear()
    results = []
    for r in records:
        seq = safe_write(r["key"], r["value"])
        results.append({"key": r["key"], "seq": seq})
    return {"results": results, "final_seq": get_seq()}
