import random
from store import insert, exists, get


def write_record(key, value):
    if random.random() < 0.3:
        raise ConnectionError("transient write failure")
    return insert(key, value)


def write_with_retry(key, value, max_retries=3):
    for attempt in range(max_retries):
        try:
            return write_record(key, value)
        except ConnectionError:
            continue
    raise ConnectionError(f"failed after {max_retries} retries")


def safe_write(key, value, max_retries=3):
    """
    Idempotent write: if the key already exists, return its seq.
    Otherwise attempt to write with retries.
    """
    if exists(key):
        existing = get(key)
        return existing["seq"]
    return write_with_retry(key, value, max_retries=max_retries)


