from writer import write_with_retry, safe_write
from store import get_seq, clear, get


def ingest_batch(records, max_batch_retries=3, per_write_retries=3):
    """
    Ingest a batch of records. Be robust to transient write failures by
    using per-write retries and batch-level retries. We clear once at
    the start (fresh run), then preserve any progress across retries by
    not clearing again and by using idempotent safe_write behavior.

    The final results are assembled from the authoritative store
    state to ensure the returned seq values reflect the actual stored
    records.
    """
    clear()

    processed = set()

    for attempt in range(max_batch_retries):
        try:
            for r in records:
                k = r["key"]
                if k in processed:
                    continue
                try:
                    seq = write_with_retry(k, r["value"], max_retries=per_write_retries)
                except ConnectionError:
                    # fallback to safe_write which will detect existing writes
                    # or perform its own retries to insert.
                    seq = safe_write(k, r["value"], max_retries=per_write_retries)
                processed.add(k)
            # All records processed; construct results from store to ensure order
            results = []
            for r in records:
                entry = get(r["key"]) or {}
                results.append({"key": r["key"], "seq": entry.get("seq")})
            return {"results": results, "final_seq": get_seq()}
        except ConnectionError:
            # transient failure during this attempt; try the batch again
            continue

    raise ConnectionError(f"batch failed after {max_batch_retries} retries")


def ingest_safe(records):
    clear()
    results = []
    for r in records:
        seq = safe_write(r["key"], r["value"])
        results.append({"key": r["key"], "seq": seq})
    return {"results": results, "final_seq": get_seq()}"}

