from collections.abc import Mapping


def _normalize_key(key):
    """Return a hashable version of key for common unhashable inputs.

    - If key is already hashable, return it.
    - If it's a list, convert to tuple.
    - If it's a set, convert to frozenset.
    - Otherwise fall back to repr(key) as a stable string key.
    """
    try:
        hash(key)
        return key
    except TypeError:
        if isinstance(key, list):
            return tuple(key)
        if isinstance(key, set):
            return frozenset(key)
        return repr(key)


def update_value(store, key, value):
    """Update a mapping-like store with key->value and return (store, log_entry).

    If store is None, a new dict is created and returned. If store is a Mapping
    but does not support item assignment, a new dict copy is created with the
    update applied. For non-mapping, non-assignable stores a TypeError is raised.
    """
    # Normalize key to something hashable for common cases.
    key = _normalize_key(key)

    # If caller passed None, create a fresh dict.
    if store is None:
        store = {}

    # Try in-place assignment first.
    try:
        store[key] = value
    except TypeError:
        # If store is a Mapping but not assignable, create a mutable copy and update.
        if isinstance(store, Mapping):
            new_store = dict(store)
            new_store[key] = value
            store = new_store
        else:
            raise TypeError("store must be a mutable mapping or None")

    return store, {"key": key, "value": value}
```

