from dataclasses import dataclass
from typing import Mapping, Union, Iterable


class InsufficientFundsError(ValueError):
    """Raised when an account does not have enough balance for a withdrawal/transfer."""


@dataclass
class Account:
    """Simple account model with a numeric balance."""

    balance: float = 0.0

    def deposit(self, amount: float) -> None:
        if amount <= 0:
            raise ValueError("deposit amount must be positive")
        self.balance += amount

    def withdraw(self, amount: float) -> None:
        if amount <= 0:
            raise ValueError("withdrawal amount must be positive")
        if self.balance < amount:
            raise InsufficientFundsError("insufficient funds")
        self.balance -= amount


# Accept either Account instances or mappings with a 'balance' key to remain compatible with
# the original dict-based usage.
AccountLike = Union[Account, Mapping]


def _get_balance(account: AccountLike) -> float:
    if isinstance(account, Account):
        return account.balance
    try:
        return float(account["balance"])
    except Exception as exc:
        raise TypeError("account must be an Account or a mapping with a 'balance' key") from exc


def _add_balance(account: AccountLike, delta: float) -> None:
    if isinstance(account, Account):
        account.balance += delta
    else:
        # mapping-based account: update the 'balance' entry in-place
        if "balance" not in account:
            raise TypeError("account mapping must contain a 'balance' key")
        account["balance"] = account.get("balance", 0) + delta


def transfer(src: AccountLike, dst: AccountLike, amount: float) -> None:
    """Transfer `amount` from `src` to `dst`.

    Works with Account objects or dict-like objects that contain a 'balance' key.
    Raises InsufficientFundsError if the source doesn't have enough balance.
    Raises ValueError for non-positive amounts.
    """
    if amount <= 0:
        raise ValueError("amount must be positive")

    src_balance = _get_balance(src)
    if src_balance < amount:
        raise InsufficientFundsError("insufficient funds")

    # perform the transfer
    _add_balance(src, -amount)
    _add_balance(dst, amount)


def get_total(*accounts: AccountLike) -> float:
    """Return the sum of balances for the provided accounts.

    Accepts a variable number of Account or mapping-like accounts.
    """
    return sum(_get_balance(a) for a in accounts)


