from typing import Any, Iterable, MutableMapping


def _balance_of(account: MutableMapping[str, Any]) -> float:
    """Return the numeric 'balance' from an account mapping.

    Raises TypeError if the account is not a mapping with a numeric 'balance'.
    """
    if not isinstance(account, MutableMapping):
        raise TypeError("account must be a mutable mapping with a 'balance' key")
    if 'balance' not in account:
        raise TypeError("account mapping must contain a 'balance' key")
    balance = account['balance']
    if not isinstance(balance, (int, float)):
        raise TypeError("account['balance'] must be a number")
    return float(balance)


def transfer(src: MutableMapping[str, Any], dst: MutableMapping[str, Any], amount: float) -> None:
    """Transfer amount from src to dst in-place.

    Raises ValueError for non-positive amounts or insufficient funds and TypeError
    if the accounts do not expose a numeric 'balance'.
    """
    if not isinstance(amount, (int, float)):
        raise TypeError('amount must be a number')
    amount = float(amount)
    if amount <= 0:
        raise ValueError('amount must be positive')

    if _balance_of(src) < amount:
        raise ValueError('insufficient funds')

    # perform the in-place transfer
    src['balance'] = _balance_of(src) - amount
    dst['balance'] = _balance_of(dst) + amount


def get_total(*accounts: Iterable[MutableMapping[str, Any]]) -> float:
    """Return the sum of balances for the provided accounts."""
    return sum(_balance_of(a) for a in accounts)


