from typing import Any, Mapping, MutableMapping, Tuple

_VALID_TRANSITIONS: Mapping[str, Tuple[str, ...]] = {
    "draft": ("submitted",),
    "submitted": ("approved", "rejected"),
    "approved": (),
    "rejected": (),
}


class InvalidTransition(ValueError):
    """Raised when an invalid state transition is attempted."""


def _get_status(item: Any) -> str:
    if isinstance(item, Mapping):
        try:
            return item["status"]
        except KeyError:
            raise KeyError("item mapping must contain a 'status' key")
    if hasattr(item, "status"):
        return getattr(item, "status")
    raise TypeError("item must be a mapping with a 'status' key or have a 'status' attribute")


def _set_status(item: Any, new_status: str) -> None:
    if isinstance(item, MutableMapping):
        item["status"] = new_status
        return
    if hasattr(item, "status"):
        setattr(item, "status", new_status)
        return
    raise TypeError("item must be a mapping with a 'status' key or have a 'status' attribute")


def can_transition(item: Any, new_status: str) -> bool:
    """Return True if item can transition to new_status from its current status."""
    current = _get_status(item)
    allowed = _VALID_TRANSITIONS.get(current, ())
    return new_status in allowed


def transition(item: Any, new_status: str) -> None:
    """Perform a state transition on item.

    The item can be a mapping (e.g. dict) with a 'status' key or an object with a 'status' attribute.
    Raises InvalidTransition if the transition is not allowed.
    Raises KeyError or TypeError if item does not expose 'status'.
    """
    current = _get_status(item)
    allowed = _VALID_TRANSITIONS.get(current, ())
    if new_status not in allowed:
        raise InvalidTransition(f"cannot go from {current!r} to {new_status!r}")
    _set_status(item, new_status)
